%%%%%%%%%% Function LabVnmbV01.m %%%%%%%%%%% Function Lab view number, ver.1% Kei Nakamura% Created on Tuesday, September 9th 2008.% Modified on %% function returns string number in labview format (tony)function strNmb = fLabVNmb(nmb)  %function headerif nmb<10    strNmb = ['00',num2str(nmb)];elseif nmb<100    strNmb = ['0',num2str(nmb)];else    strNmb = [num2str(nmb)];end
